<template><div class="panel"><div class="section-head"><div><h2>{{ t('logs.onlineTitle') }}</h2><p>{{ t('logs.onlineDescription') }}</p></div><el-button @click="load">{{ t('common.refresh') }}</el-button></div><el-table :data="rows"><el-table-column prop="username" :label="t('common.user')"/><el-table-column prop="ipAddress" :label="t('common.ip')"/><el-table-column prop="userAgent" :label="t('common.client')" show-overflow-tooltip/><el-table-column prop="loginAt" :label="t('logs.loginTime')"/><el-table-column prop="lastActiveAt" :label="t('logs.lastActive')"/><el-table-column :label="t('common.operation')"><template #default="s"><el-button v-if="auth.hasPermission('system:session:terminate')" link type="danger" @click="terminate(s.row)">{{ t('logs.forceLogout') }}</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next"/></div></template>
<script setup>import{computed,onMounted,reactive,ref}from'vue';import{ElMessageBox}from'element-plus';import{useI18n}from'vue-i18n';import http from'../api/http';import{useAuthStore}from'../stores/auth';const{t}=useI18n();const auth=useAuthStore(),allSessions=ref([]);const query=reactive({page:1,size:5});const total=computed(()=>allSessions.value.length);const rows=computed(()=>allSessions.value.slice((query.page-1)*query.size,query.page*query.size));async function load(){allSessions.value=(await http.get('/system/online-sessions')).data}/** 强制撤销指定会话。 */async function terminate(row){await ElMessageBox.confirm(t('common.confirmTerminate',{name:row.username}),t('common.confirm'),{type:'warning'});await http.delete(`/system/online-sessions/${row.tokenId}`);await load()}onMounted(load)</script>
<!-- 在线用户页面：查看会话并执行强制下线。 -->
